## 2.  The C/C++ stub (`pcapng_stubs.cpp`)

> **NOTE** – The file is deliberately written as a *C++* source file
> (`.cpp`/`.cc`) because the underlying library is C++.  The public
> symbols are still declared with `extern "C"` so that the OCaml
> runtime can find them.  When you compile with `ocamlopt` you must
> pass a C++ compiler (`-ccopt -lstdc++` or similar).

```cpp
/* ----------------------------------------------------------------------
 *  pcapng_stubs.cpp
 *
 *  OCaml <-> C++ glue for libpcapng.
 *
 *  Build (example with ocamlopt):
 *
 *    ocamlopt -c -I +camlp4 pcapng_stubs.cpp   # compile the stub
 *    ocamlopt -o pcapng.cmx pcapng.cmx pcapng_stubs.o -cclib -lstdc++
 *
 *  If you use Dune, add:
 *
 *    (foreign_stubs
 *      (language cxx)
 *      (names pcapng_stubs))
 *
 * ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <cstddef>
#include <cstdint>
#include <cstdio>
#include <cstring>
#include <string>
#include <vector>
#include <exception>

/* ----------------------------------------------------------------------
 *  Mock of the real libpcapng API.
 *
 *  Replace this section with the real header(s) from libpcapng.
 * ---------------------------------------------------------------------- */

namespace libpcapng {

struct Frame {
    const uint8_t* data;   // pointer into internal buffer (owned by Reader)
    size_t          len;    // length of data
    uint64_t        ts;     // timestamp in nanoseconds
};

class Reader {
public:
    explicit Reader(const std::string& filename) {
        // In the real library you would open the file and parse the headers.
        // Here we just fake a few frames for demonstration.
        if (filename.empty())
            throw std::runtime_error("empty filename");
        // Fake data:
        static const uint8_t pkt1[] = {0xde,0xad,0xbe,0xef};
        static const uint8_t pkt2[] = {0xca,0xfe,0xba,0xbe,0x00,0x01};
        frames_.push_back({pkt1, sizeof(pkt1), 1'600'000'000'000ULL});
        frames_.push_back({pkt2, sizeof(pkt2), 1'600'000'001'000ULL});
        cur_ = frames_.begin();
    }

    // non‑copyable (important for custom blocks)
    Reader(const Reader&) = delete;
    Reader& operator=(const Reader&) = delete;

    bool has_next() const { return cur_ != frames_.end(); }

    Frame next() {
        if (!has_next())
            throw std::out_of_range("no more frames");
        Frame f = *cur_;
        ++cur_;
        return f;
    }

    // Reset iterator – useful for [next] after a previous walk.
    void rewind() { cur_ = frames_.begin(); }

private:
    std::vector<Frame> frames_;
    std::vector<Frame>::iterator cur_;
};

} // namespace libpcapng

/* ----------------------------------------------------------------------
 *  OCaml custom block for the Reader.
 *
 *  The block holds a pointer to a heap‑allocated Reader object.
 *  The custom ops take care of finalisation (freeing the C++ object)
 *  and of reporting the block as “no‑heap” – i.e. the GC never scans
 *  the memory pointed to by the Reader.
 * ---------------------------------------------------------------------- */

static void pc_reader_finalize(value v) {
    libpcapng::Reader* r = reinterpret_cast<libpcapng::Reader*>(Data_custom_val(v));
    delete r;
}

/* No special comparison, hashing or serialization needed */
static struct custom_operations pc_reader_ops = {
    "pcapng.reader",
    pc_reader_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Helper to extract the pointer from the OCaml value (with safety) */
static libpcapng::Reader* Reader_val(value v) {
    return reinterpret_cast<libpcapng::Reader*>(Data_custom_val(v));
}

/* ----------------------------------------------------------------------
 *  Helper: build an OCaml [frame] record from a C++ Frame.
 *
 *  The record layout must match the .mli definition:
 *
 *    type frame = { data : bytes; timestamp : int64 }
 *
 *  We allocate a two‑field block, then fill the fields.
 * ---------------------------------------------------------------------- */

static value caml_frame_of_cpp(const libpcapng::Frame& f) {
    CAMLparam0();
    CAMLlocal2(ocaml_bytes, ocaml_frame);

    /* 1️⃣  Build a fresh OCaml Bytes.t containing a copy of the packet */
    ocaml_bytes = caml_alloc_string(f.len);
    memcpy(String_val(ocaml_bytes), f.data, f.len);

    /* 2️⃣  Allocate the record {data; timestamp} */
    ocaml_frame = caml_alloc(2, 0);          /* 2 fields, tag 0 = record */
    Store_field(ocaml_frame, 0, ocaml_bytes);
    Store_field(ocaml_frame, 1, caml_copy_int64((int64_t)f.ts));

    CAMLreturn(ocaml_frame);
}

/* ----------------------------------------------------------------------
 *  OCaml‑exposed primitives
 * ---------------------------------------------------------------------- */

/*  val open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_handle);
    const char* path = String_val(v_path);
    try {
        libpcapng::Reader* r = new libpcapng::Reader(std::string(path));
        v_handle = caml_alloc_custom(&pc_reader_ops, sizeof(void*), 0, 1);
        Data_custom_val(v_handle) = reinterpret_cast<char*>(r);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
    CAMLreturn(v_handle);
}

/*  val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    /* The custom finaliser already frees the Reader, but we allow
       an explicit close that clears the pointer so that later use
       raises a clear error rather than seg‑faulting. */
    libpcapng::Reader* r = Reader_val(v_handle);
    if (r) {
        delete r;
        Data_custom_val(v_handle) = nullptr;
    }
    CAMLreturn(Val_unit);
}

/*  val next : t -> frame option */
extern "C" CAMLprim value caml_pcapng_next(value v_handle) {
    CAMLparam1(v_handle);
    CAMLlocal1(v_res);
    libpcapng::Reader* r = Reader_val(v_handle);
    if (!r) caml_failwith("Pcapng.Reader already closed");

    if (!r->has_next()) {
        /* None */
        v_res = Val_int(0);   /* 0 = None */
    } else {
        libpcapng::Frame f = r->next();
        value ocaml_f = caml_frame_of_cpp(f);
        /* Some f */
        v_res = caml_alloc(1, 0);   /* option tag 0 = Some */
        Store_field(v_res, 0, ocaml_f);
    }
    CAMLreturn(v_res);
}

/*  val iter : t -> (frame -> unit) -> unit
 *
 *  The heavy lifting happens here: we iterate in C++ and invoke the OCaml
 *  callback for each frame.  The callback may raise; we stop iterating
 *  and re‑raise the exception to the OCaml side.
 */
extern "C" CAMLprim value caml_pcapng_iter(value v_handle, value v_cb) {
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_dummy);   /* dummy used to keep the callback rooted */
    libpcapng::Reader* r = Reader_val(v_handle);
    if (!r) caml_failwith("Pcapng.Reader already closed");

    /* The callback must be kept alive across the C++ loop.
       caml_callback_exn does that automatically, but we also need to
       protect the callback from the GC while we are in the loop. */
    caml_register_global_root(&v_cb);

    try {
        while (r->has_next()) {
            libpcapng::Frame f = r->next();
            value ocaml_f = caml_frame_of_cpp(f);
            /* Call the OCaml function.  caml_callback_exn returns a value
               (here we ignore it) and propagates any exception as a
               CAMLexception. */
            v_dummy = caml_callback_exn(v_cb, ocaml_f);
            if (Is_exception_result(v_dummy)) {
                /* Propagate the exception out of the loop. */
                raise_exception(v_dummy);
            }
        }
    } catch (const std::exception& ex) {
        caml_unregister_global_root(&v_cb);
        caml_failwith(ex.what());
    }

    caml_unregister_global_root(&v_cb);
    CAMLreturn(Val_unit);
}

/*  val fold : t -> ('a -> frame -> 'a) -> 'a -> 'a
 *
 *  Implemented in terms of [iter] for simplicity.  It is a thin wrapper
 *  that accumulates a result in an OCaml closure.
 */
extern "C" CAMLprim value caml_pcapng_fold(value v_handle,
                                          value v_f,
                                          value v_acc) {
    CAMLparam3(v_handle, v_f, v_acc);
    CAMLlocal2(v_state, v_tmp);
    v_state = v_acc;   /* current accumulator */

    /* The folding function expects: f acc frame -> acc' */
    /* We build a small wrapper closure that captures [v_f] and updates
       [v_state] on each iteration. */
    value fold_cb = caml_alloc_closure(2, 0);
    Store_field(fold_cb, 0, v_f);        /* user supplied f */
    Store_field(fold_cb, 1, v_state);    /* mutable slot for accumulator */

    /* Helper that OCaml will call on each frame. */
    static value fold_helper(value closure, value frame) {
        CAMLparam2(closure, frame);
        CAMLlocal1(new_acc);
        value f = Field(closure, 0);
        value acc_slot = Field(closure, 1);
        value acc = acc_slot;
        new_acc = caml_callback2(f, acc, frame);
        Store_field(closure, 1, new_acc);
        CAMLreturn(Val_unit);
    }

    /* Register the helper as a global root so that the GC can see it
       while we are inside the C++ loop. */
    caml_register_global_root(&fold_cb);
    caml_register_global_root(&v_f);

    /* Run the iterator, feeding each frame to the helper */
    libpcapng::Reader* r = Reader_val(v_handle);
    if (!r) caml_failwith("Pcapng.Reader already closed");

    try {
        while (r->has_next()) {
            libpcapng::Frame f = r->next();
            value ocaml_f = caml_frame_of_cpp(f);
            v_tmp = caml_callback2(v_f, Field(fold_cb, 1), ocaml_f);
            Store_field(fold_cb, 1, v_tmp);   /* update accumulator */
        }
    } catch (const std::exception& ex) {
        caml_unregister_global_root(&fold_cb);
        caml_unregister_global_root(&v_f);
        caml_failwith(ex.what());
    }

    v_state = Field(fold_cb, 1);
    caml_unregister_global_root(&fold_cb);
    caml_unregister_global_root(&v_f);
    CAMLreturn(v_state);
}

/* ----------------------------------------------------------------------
 *  Registration table (optional, but handy when using the C stub
 *  directly via Dynlink or when building a static library).
 * ---------------------------------------------------------------------- */

static struct caml_named_value {
    const char *name;
    value (*fn)(value);
} caml_named_values[] = {
    {"Pcapng.open_file", caml_pcapng_open_file},
    {"Pcapng.close",     caml_pcapng_close},
    {"Pcapng.next",      caml_pcapng_next},
    {"Pcapng.iter",      caml_pcapng_iter},
    {"Pcapng.fold",      caml_pcapng_fold},
    {NULL, NULL}
};

extern "C" void caml_init_pcapng_stubs(void) {
    for (int i = 0; caml_named_values[i].name != NULL; ++i) {
        caml_register_named_value(caml_named_values[i].name,
                                  caml_named_values[i].fn);
    }
}

/* End of pcapng_stubs.cpp */
```

